// Extração de texto do PDF usando pdf-parse
const PDFParser = require('pdf-parse');

const items = [];

for (const item of $input.all()) {
  const binaryData = await this.helpers.getBinaryDataBuffer(item.binary.data);
  const pdfData = await PDFParser(binaryData);

  // Divide o texto em páginas
  const pages = pdfData.text.split('\f');

  pages.forEach((pageText, index) => {
    if (pageText.trim()) {
      items.push({
        json: {
          text: pageText.trim(),
          page: index + 1,
          totalPages: pages.length
        }
      });
    }
  });
}

return items;

// Chunking inteligente com overlap
const chunkSize = 1000;
const chunkOverlap = 200;

const items = [];

for (const item of $input.all()) {
  const text = item.json.text;
  const page = item.json.page;

  let start = 0;
  let chunkIndex = 0;

  while (start < text.length) {
    const end = Math.min(start + chunkSize, text.length);
    const chunk = text.substring(start, end);

    items.push({
      json: {
        content: chunk,
        page: page,
        chunkIndex: chunkIndex,
        metadata: {
          page: page,
          chunk: chunkIndex,
          charStart: start,
          charEnd: end
        }
      }
    });

    start += (chunkSize - chunkOverlap);
    chunkIndex++;
  }
}

return items;

// Preparar dados para Pinecone
const items = [];

for (const item of $input.all()) {
  const embedding = item.json.data[0].embedding;
  const metadata = $('Chunking Inteligente').item(item.index).json.metadata;
  const content = $('Chunking Inteligente').item(item.index).json.content;

  items.push({
    json: {
      id: `chunk-${metadata.page}-${metadata.chunk}`,
      values: embedding,
      metadata: {
        ...metadata,
        text: content
      }
    }
  });
}

return items;

// Gerar embedding da pergunta
const question = $input.first().json.body.question;

return [{
  json: {
    question: question,
    user_id: $input.first().json.body.user_id,
    session_id: $input.first().json.body.session_id || 'default'
  }
}];

// Validação Anti-Alucinação
const question = $('Preparar Pergunta').item.json.question;
const results = $input.first().json.matches || [];

// Verifica se há documentos relevantes
if (!results || results.length === 0) {
  return [{
    json: {
      response: "Desculpe, não encontrei informações sobre isso no ebook médico. Por favor, reformule sua pergunta ou consulte diretamente o material.",
      confidence: 0,
      sources: [],
      hallucination_risk: "HIGH",
      error: true,
      validated: false
    }
  }];
}

// Calcula score de confiança
const avgScore = results.reduce((sum, doc) => sum + (doc.score || 0), 0) / results.length;

// Threshold de confiança: 0.7
if (avgScore < 0.7) {
  return [{
    json: {
      response: "As informações encontradas têm baixa relevância. Recomendo reformular a pergunta de forma mais específica.",
      confidence: avgScore,
      sources: [],
      hallucination_risk: "MEDIUM",
      error: true,
      validated: false
    }
  }];
}

// Prepara contexto para LLM
const context = results.map(doc => ({
  content: doc.metadata.text,
  page: doc.metadata.page,
  chunk: doc.metadata.chunk,
  score: doc.score
}));

const contextText = context.map((c, i) => 
  `[Fonte ${i+1} - Página ${c.page}]:\n${c.content}`
).join('\n\n');

return [{
  json: {
    question,
    context: contextText,
    contextArray: context,
    confidence: avgScore,
    hallucination_risk: "LOW",
    validated: true,
    error: false
  }
}];

