// Pós-processamento e verificação final
const llmResponse = $input.first().json.choices[0].message.content;
const validation = $('Validação Anti-Alucinação').item.json;

// Se já teve erro na validação, retorna erro
if (validation.error) {
  return [{
    json: {
      ...validation,
      timestamp: new Date().toISOString()
    }
  }];
}

// Extrai citações da resposta
const citations = [];
const citationRegex = /\[Página (\d+)\]/g;
let match;

while ((match = citationRegex.exec(llmResponse)) !== null) {
  citations.push({
    page: parseInt(match[1])
  });
}

// Verifica se há citações (obrigatório)
if (citations.length === 0) {
  return [{
    json: {
      response: "ERRO: Resposta sem citação adequada. Por favor, reformule a pergunta.",
      error: true,
      reason: "missing_citations",
      original_response: llmResponse,
      validated: false
    }
  }];
}

// Verifica frases suspeitas de alucinação
const suspiciousPhrases = [
  "eu acho",
  "provavelmente",
  "pode ser",
  "geralmente",
  "na minha experiência",
  "é comum que"
];

const hasSuspiciousContent = suspiciousPhrases.some(phrase => 
  llmResponse.toLowerCase().includes(phrase)
);

if (hasSuspiciousContent) {
  return [{
    json: {
      response: "AVISO: Resposta contém linguagem não assertiva. Reformulando...",
      error: true,
      reason: "suspicious_language",
      original_response: llmResponse,
      validated: false
    }
  }];
}

return [{
  json: {
    response: llmResponse,
    citations: citations,
    confidence: validation.confidence,
    sources: validation.contextArray,
    validated: true,
    error: false,
    timestamp: new Date().toISOString()
  }
}];
